
class Scheduling {final Map<String, String>? nodeSelector; final List<Toleration>? tolerations; Scheduling({this.nodeSelector, this.tolerations}); factory Scheduling.fromJson(Map<String, dynamic> json) {return Scheduling(nodeSelector: json['nodeSelector'] != null ? Map<String, String>.from(json['nodeSelector']) : null, tolerations: json['tolerations'] != null ? (json['tolerations'] as List).map((e) => Toleration.fromJson(e)).toList() : null);} Map<String, dynamic> toJson() {return {if (nodeSelector != null) 'nodeSelector' : nodeSelector, if (tolerations != null) 'tolerations' : tolerations!.map((e) => e.toJson()).toList()};}}
